class LoggingNavigatorObserver extends NavigatorObserver {
  @override
  void didPush(Route<dynamic> route, Route<dynamic>? previousRoute) {
    AppLogger.userInteraction(
      'navigation_push',
      properties: {
        'route': route.settings.name ?? route.toString(),
        'previousRoute': previousRoute?.settings.name ?? previousRoute?.toString(),
      },
    );
    super.didPush(route, previousRoute);
  }

  @override
  void didPop(Route<dynamic> route, Route<dynamic>? previousRoute) {
    AppLogger.userInteraction(
      'navigation_pop',
      properties: {
        'route': route.settings.name ?? route.toString(),
        'previousRoute': previousRoute?.settings.name ?? previousRoute?.toString(),
      },
    );
    super.didPop(route, previousRoute);
  }

  @override
  void didReplace({Route<dynamic>? newRoute, Route<dynamic>? oldRoute}) {
    AppLogger.userInteraction(
      'navigation_replace',
      properties: {
        'newRoute': newRoute?.settings.name ?? newRoute?.toString(),
        'oldRoute': oldRoute?.settings.name ?? oldRoute?.toString(),
      },
    );
    super.didReplace(newRoute: newRoute, oldRoute: oldRoute);
  }
}

class LoggingTapListener extends StatelessWidget {
  final Widget child;
  final String screenName;

  const LoggingTapListener({
    super.key,
    required this.child,
    required this.screenName,
  });

  @override
  Widget build(BuildContext context) {
    return Listener(
      behavior: HitTestBehavior.translucent,
      onPointerDown: (event) {
        AppLogger.userInteraction(
          'pointer_down',
          screen: screenName,
          properties: {
            'x': event.position.dx,
            'y': event.position.dy,
          },
        );
      },
      child: child,
    );
  }
}